function svgIcon(path, color, size) {
  var s = size || 24;
  return React.createElement('svg', { width: s, height: s, viewBox: '0 0 24 24', fill: color || '#fff' },
    React.createElement('path', { d: path }));
}

// ============================================================
// 状态管理
// ============================================================
var _customState = {
  currentSlide: 1,
  totalSlides: 23,
  touchStartX: 0
};

export function getCustomState(key) {
  if (key) return _customState[key];
  return Object.assign({}, _customState);
}

export function setCustomState(newState) {
  Object.keys(newState).forEach(function(key) {
    _customState[key] = newState[key];
  });
  this.forceUpdate();
}

export function forceUpdate() {
  this.setState({ timestamp: new Date().getTime() });
}

// ============================================================
// 导航
// ============================================================
export function goToSlide(n) {
  if (n < 1 || n > _customState.totalSlides) return;
  _customState.currentSlide = n;
  this.forceUpdate();
}

export function changeSlide(dir) {
  var next = _customState.currentSlide + dir;
  if (next < 1) next = 1;
  if (next > _customState.totalSlides) next = _customState.totalSlides;
  this.goToSlide(next);
}

// ============================================================
// 生命周期
// ============================================================
export function didMount() {
  var self = this;
  var devtool = document.getElementById('__lowcode_devtool_switch__');
  if (devtool) devtool.style.display = 'none';

  self._handleKeyDown = function(e) {
    if (e.key === 'ArrowRight' || e.key === 'ArrowDown' || e.key === ' ' || e.key === 'PageDown') {
      e.preventDefault(); self.changeSlide(1);
    } else if (e.key === 'ArrowLeft' || e.key === 'ArrowUp' || e.key === 'PageUp') {
      e.preventDefault(); self.changeSlide(-1);
    } else if (e.key === 'Home') {
      e.preventDefault(); self.goToSlide(1);
    } else if (e.key === 'End') {
      e.preventDefault(); self.goToSlide(_customState.totalSlides);
    }
  };
  document.addEventListener('keydown', self._handleKeyDown);

  self._handleTouchStart = function(e) { _customState.touchStartX = e.changedTouches[0].screenX; };
  self._handleTouchEnd = function(e) {
    var diff = _customState.touchStartX - e.changedTouches[0].screenX;
    if (Math.abs(diff) > 50) { self.changeSlide(diff > 0 ? 1 : -1); }
  };
  document.addEventListener('touchstart', self._handleTouchStart);
  document.addEventListener('touchend', self._handleTouchEnd);

  setTimeout(function() { self.initParticles(); }, 500);
}

export function didUnmount() {
  document.removeEventListener('keydown', this._handleKeyDown);
  document.removeEventListener('touchstart', this._handleTouchStart);
  document.removeEventListener('touchend', this._handleTouchEnd);
  if (_customState._animFrame) cancelAnimationFrame(_customState._animFrame);
}

// ============================================================
// 粒子系统
// ============================================================
export function initParticles() {
  var canvas = document.getElementById('ppt-particles');
  if (!canvas) return;
  var ctx = canvas.getContext('2d');
  var particles = [];
  var COUNT = 50;
  var DIST = 130;
  var colors = ['59,130,246', '139,92,246', '16,185,129'];
  function resize() { canvas.width = window.innerWidth; canvas.height = window.innerHeight; }
  function init() {
    particles = [];
    for (var i = 0; i < COUNT; i++) {
      particles.push({ x: Math.random() * canvas.width, y: Math.random() * canvas.height, vx: (Math.random() - 0.5) * 0.4, vy: (Math.random() - 0.5) * 0.4, r: Math.random() * 1.5 + 0.5, c: colors[Math.floor(Math.random() * colors.length)] });
    }
  }
  function draw() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    for (var i = 0; i < particles.length; i++) {
      var p = particles[i];
      p.x += p.vx; p.y += p.vy;
      if (p.x < 0 || p.x > canvas.width) p.vx *= -1;
      if (p.y < 0 || p.y > canvas.height) p.vy *= -1;
      ctx.beginPath(); ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(' + p.c + ',0.5)'; ctx.fill();
    }
    for (var i = 0; i < particles.length; i++) {
      for (var j = i + 1; j < particles.length; j++) {
        var dx = particles[i].x - particles[j].x;
        var dy = particles[i].y - particles[j].y;
        var d = Math.sqrt(dx * dx + dy * dy);
        if (d < DIST) {
          ctx.beginPath(); ctx.moveTo(particles[i].x, particles[i].y); ctx.lineTo(particles[j].x, particles[j].y);
          ctx.strokeStyle = 'rgba(59,130,246,' + (0.08 * (1 - d / DIST)).toFixed(3) + ')'; ctx.lineWidth = 0.5; ctx.stroke();
        }
      }
    }
    _customState._animFrame = requestAnimationFrame(draw);
  }
  resize(); init(); draw();
  window.addEventListener('resize', function() { resize(); init(); });
}

