export function renderBgLayers(isChapter) {
  return (
    <div>
      <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', pointerEvents: 'none', background: 'radial-gradient(ellipse at 20% 30%,rgba(59,130,246,.15) 0%,transparent 50%),radial-gradient(ellipse at 80% 70%,rgba(139,92,246,.12) 0%,transparent 50%),radial-gradient(ellipse at 50% 50%,rgba(11,15,25,.8) 0%,rgba(0,0,0,1) 100%)' }} />
      {isChapter && <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', pointerEvents: 'none', backgroundImage: 'linear-gradient(rgba(59,130,246,.03) 1px,transparent 1px),linear-gradient(90deg,rgba(59,130,246,.03) 1px,transparent 1px)', backgroundSize: '60px 60px', animation: 'gridMove 20s linear infinite' }} />}
      {isChapter && <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', pointerEvents: 'none', background: 'radial-gradient(circle at 50% 50%,rgba(59,130,246,.08) 0%,transparent 70%)', animation: 'chapterGlow 6s ease-in-out infinite' }} />}
    </div>
  );
}

export function renderSlideWrapper(slideNum, content) {
  var cur = _customState.currentSlide;
  if (cur !== slideNum) return null;
  var isChapter = chapterSlides.indexOf(slideNum) >= 0;
  var tr = slideTransitions[slideNum] || 'fadeIn';
  var trStyle = { animation: tr + ' 1.2s cubic-bezier(.25,.46,.45,.94) both' };
  var bgImg = chapterImages[slideNum];
  return (
    <div style={Object.assign({ width: '100vw', height: '100vh', position: 'absolute', top: 0, left: 0, overflow: 'hidden', display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center' }, trStyle)}>
      {this.renderBgLayers(isChapter)}
      {bgImg && <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', backgroundImage: 'url(' + bgImg + ')', backgroundSize: 'cover', backgroundPosition: 'center', opacity: isChapter ? 0.15 : 0.1, zIndex: 0 }} />}
      <div style={{ position: 'relative', zIndex: 10, maxWidth: '1600px', margin: 'auto', padding: '50px 70px', display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', textAlign: 'center', width: '100%' }}>
        {content}
      </div>
    </div>
  );
}

export function renderGenericSlide(num, partTag, title, subtitle, bodyJsx) {
  return this.renderSlideWrapper(num,
    <div style={{ width: '100%' }}>
      {partTag && <div style={S.tg}>{partTag}</div>}
      <div style={S.stSts}>{title}</div>
      {subtitle && <div style={S.ss}>{subtitle}</div>}
      <div style={{ width: '100%', animation: 'fu 1.2s ease-out .8s both' }}>{bodyJsx}</div>
    </div>
  );
}

